let marks = 78;

// Simple if
if (marks >= 40) {
  console.log("Passed!");
}

// if-else
if (marks >= 90) {
  console.log("Excellent!");
} else {
  console.log("Keep working hard.");
}

// else-if chain (grade calculator)
let grade;
if (marks >= 90) {
  grade = "A";
} else if (marks >= 80) {
  grade = "B";
} else if (marks >= 70) {
  grade = "C";
} else if (marks >= 60) {
  grade = "D";
} else {
  grade = "F";
}
console.log(`Marks: ${marks}, Grade: ${grade}`);

